import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract TeamVestingVault is ReentrancyGuard {
    address private _owner;
    mapping(address => uint256) public allocation;
    mapping(address => uint256) public releaseBlock;
    mapping(address => uint256) public withdrawn;

    event InvestorAdded(address indexed investor, uint256 amount, uint256 unlockBlock);
    event Withdrawn(address indexed investor, uint256 amount);

    constructor() {
        _owner = msg.sender;
    }

    modifier onlyOwner() {
        require(msg.sender == _owner, "Not owner");
        _;
    }

    // Reentrancy Guard
    bool private locked;
    modifier noReentrancy() {
        require(!locked, "No reentrancy");
        locked = true;
        _;
        locked = false;
    }

    // Function to add an investor
    function addInvestor(address investor, uint256 amount, uint256 unlockBlock) public onlyOwner {
        allocation[investor] = amount;
        releaseBlock[investor] = unlockBlock;
        emit InvestorAdded(investor, amount, unlockBlock);
    }

    // Function to withdraw tokens
    function withdraw() public noReentrancy {
        require(block.number >= releaseBlock[msg.sender], "Release block not reached");
        uint256 amountToWithdraw = allocation[msg.sender] - withdrawn[msg.sender];
        require(amountToWithdraw > 0, "Nothing to withdraw");

        withdrawn[msg.sender] += amountToWithdraw;
        // Transfer tokens (assuming ERC20 token)
